class ToolRegistry:
    """Manages system tools, converting Python functions to JSON schemas."""

    def __init__(self):
        self.tools: Dict[str, Dict[str, Any]] = {}

    def register(self, name: str, description: str, parameters: Dict[str, Any]) -> Callable:
        def decorator(func: Callable):
            self.tools[name] = {
                "func": func,
                "schema": {
                    "name": name,
                    "description": description,
                    "parameters": parameters
                }
            }
            return func
        return decorator

    def get_schemas(self) -> List[Dict[str, Any]]:
        return [tool["schema"] for tool in self.tools.values()]

    def execute(self, name: str, arguments: Dict[str, Any]) -> str:
        if name not in self.tools:
            return f"Error: Tool '{name}' is not registered."
        try:
            result = self.tools[name]["func"](**arguments)
            return json.dumps(result, ensure_ascii=False)
        except Exception as e:
            return f"Error executing tool '{name}': {str(e)}"


class HermesParser:
    """Extracts thoughts and XML-based tool invocations from Hermes output."""

    @staticmethod
    def parse_thought(text: str) -> Optional[str]:
        match = re.search(r"<thought>(.*?)</thought>", text, re.DOTALL)
        return match.group(1).strip() if match else None

    @staticmethod
    def parse_tool_calls(text: str) -> List[Tuple[str, Dict[str, Any]]]:
        # Matches patterns like: <call:tool_name>{"arg1": "val1"}</call:tool_name>
        pattern = r"<call:(\w+)>(.*?)(?:</call:\1>|$)"
        matches = re.findall(pattern, text, re.DOTALL)
        calls = []
        for tool_name, args_str in matches:
            try:
                args = json.loads(args_str.strip())
                calls.append((tool_name, args))
            except json.JSONDecodeError:
                # Fallback parser for loose JSON output
                try:
                    cleaned_args = re.sub(r'\'', '"', args_str.strip())
                    args = json.loads(cleaned_args)
                    calls.append((tool_name, args))
                except Exception:
                    # Return raw string argument wrapped if conversion fails
                    calls.append((tool_name, {"raw_argument": args_str.strip()}))
        return calls


class HermesAgent:
    """Orchestrates the entire execution sequence using Hermes XML formatting."""

    def __init__(self, registry: ToolRegistry, model: str = "hermes-3", api_url: str = "http://localhost:11434/v1"):
        self.registry = registry
        self.model = model
        self.api_url = api_url
        self.system_prompt_template = (
            "You are a highly capable AI Agent optimized for tool execution and multi-step reasoning.\n"
            "You have access to the following tools:\n"
            "<tools>\n{tools_schema}\n</tools>\n\n"
            "To solve complex problems, write out your internal thinking step-by-step using <thought> tags.\n"
            "If you need to query an external source or execute an action, call a tool using the following XML format:\n"
            "<call:tool_name>{{\"param\": \"value\"}}</call:tool_name>\n"
            "The system will execute the tool and provide the observation formatted as:\n"
            "<response:tool_name>result_data</response:tool_name>\n\n"
            "Iterate this loop until you have collected sufficient information to answer the prompt directly without calling more tools."
        )

    def generate_system_prompt(self) -> str:
        schemas = self.registry.get_schemas()
        return self.system_prompt_template.format(tools_schema=json.dumps(schemas, indent=2))

    def _query_model(self, messages: List[Dict[str, str]]) -> str:
        """Helper to send request to OpenAI-compatible endpoint (Ollama, vLLM, etc.)."""
        payload = {
            "model": self.model,
            "messages": messages,
            "temperature": 0.1,
            "stop": ["</response:"]
        }

        headers = {"Content-Type": "application/json"}
        req = urllib.request.Request(
            f"{self.api_url}/chat/completions",
            data=json.dumps(payload).encode("utf-8"),
            headers=headers,
            method="POST"
        )
        try:
            with urllib.request.urlopen(req, timeout=60) as response:
                res_data = json.loads(response.read().decode("utf-8"))
                return res_data["choices"][0]["message"]["content"]
        except urllib.error.URLError as e:
            return f"<thought>Fallback processing enabled. Host API connection failed: {str(e)}</thought>"

    def run(self, prompt: str, max_iterations: int = 5, mock_responses: Optional[List[str]] = None) -> List[Dict[str, str]]:
        """Executes the planning, execution, feedback loops."""
        messages = [
