                response_text = mock_responses[iteration - 1]
            else:
                response_text = self._query_model(messages)

            messages.append({"role": "assistant", "content": response_text})

            # Extract thought and actions
            thought = HermesParser.parse_thought(response_text)
            if thought:
                print(f"[THOUGHT] Step {iteration}: {thought}")

            tool_calls = HermesParser.parse_tool_calls(response_text)
            if not tool_calls:
                # No tool calls detected, Agent has arrived at the final answer
                print(f"[AGENT STATE] Loop terminated normally. Answer synthesized.")
                break

            # Execute tool actions and append responses
            response_payload = ""
            for name, args in tool_calls:
                print(f"[ACTION] Invoking tool '{name}' with arguments: {args}")
                observation = self.registry.execute(name, args)
                print(f"[OBSERVATION] Result: {observation}")
                response_payload += f"<response:{name}>{observation}</response:{name}>\n"

            messages.append({"role": "user", "content": response_payload.strip()})

        return messages


