class ToolRegistry:
    """Manages system tools, converting Python functions to JSON schemas."""

    def __init__(self):
        self.tools: Dict[str, Dict[str, Any]] = {}

    def register(self, name: str, description: str, parameters: Dict[str, Any]) -> Callable:
        def decorator(func: Callable):
            self.tools[name] = {
                "func": func,
                "schema": {
                    "name": name,
                    "description": description,
                    "parameters": parameters
                }
            }
            return func
        return decorator

    def get_schemas(self) -> List[Dict[str, Any]]:
        return [tool["schema"] for tool in self.tools.values()]

    def execute(self, name: str, arguments: Dict[str, Any]) -> str:
        if name not in self.tools:
            return f"Error: Tool '{name}' is not registered."
        try:
            result = self.tools[name]["func"](**arguments)
            return json.dumps(result, ensure_ascii=False)
        except Exception as e:
            return f"Error executing tool '{name}': {str(e)}"


class HermesParser:
    """Extracts thoughts and XML-based tool invocations from Hermes output."""

    @staticmethod
    def parse_thought(text: str) -> Optional[str]:
        match = re.search(r"<thought>(.*?)</thought>", text, re.DOTALL)
        return match.group(1).strip() if match else None

    @staticmethod
    def parse_tool_calls(text: str) -> List[Tuple[str, Dict[str, Any]]]:
        # Matches patterns like: <call:tool_name>{"arg1": "val1"}</call:tool_name>
        pattern = r"<call:(\w+)>(.*?)(?:</call:\1>|$)"
        matches = re.findall(pattern, text, re.DOTALL)
        calls = []
        for tool_name, args_str in matches:
            try:
                args = json.loads(args_str.strip())
                calls.append((tool_name, args))
            except json.JSONDecodeError:
                # Fallback parser for loose JSON output
                try:
                    cleaned_args = re.sub(r'\'', '"', args_str.strip())
                    args = json.loads(cleaned_args)
                    calls.append((tool_name, args))
                except Exception:
                    # Return raw string argument wrapped if conversion fails
                    calls.append((tool_name, {"raw_argument": args_str.strip()}))
        return calls


